INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05380', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '蓋嘗論天人之辨，以謂人無所不至，惟天不容偽。智可以欺王公，不可以欺豚 魚；力可以得天下，不可以得匹夫匹婦之心。所謂「人無所不至」，意指：', '["讚嘆人類人定勝天，無遠弗屆", "感佩人類意志堅定，持之以恆", "感慨人類為達目的，不擇手段", "惋惜人類自作聰明，容易被騙"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05381', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '假如你聽膩了許多牢騷，什麼「文籍雖滿腹，不如一囊錢」，什麼「羞煞文章不療 饑」之類的讀書無用論，即使有點同情，也引不起絲毫敬意。忽然聽到有詩人唱著： 「天與饑寒亦愛才」，這種比世俗感慨深一層的想法，出人意外，原來完滿的愛情 與飽足的生活，常使才子貧血，所以天與饑寒，有時是上天愛才的緣故！ 上文所謂「天與饑寒亦愛才」，其意近於：', '["飽暖思淫欲，饑寒起盜心", "憂患生於所忽，巨禍起於細微", "倉廩實而知禮節，衣食足而知榮辱", "天將降大任於斯人也，必先苦其心志"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05382', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列詩詞中無關時間的是：', '["醉和金甲舞，雷鼓動山川", "雞聲茅店月，人跡板橋霜", "寒蟬淒切，對長亭晚，驟雨初歇", "斜陽照墟落，窮巷牛羊歸。野老念牧童，倚仗候荊扉"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05383', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「機會的後腦袋是禿頭，沒有毛的，當他從你身旁經過時，必須立即一把捉住。否 則的話，就再也趕不上，只有望塵興嘆的份兒了！」（古希臘名言） 上文意旨與下列何者相同？', '["得時無怠，時不再來", "及時當勉勵，歲月不待人", "文變染乎世情，興廢繫乎時序", "雖有智慧，不如乘勢；雖有鎡基，不如待時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05384', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '英國學者邊沁建議成立一個財務自負盈虧的窮人收容所，窮人們會在收容所裡工作 過活，因而減少街頭的乞丐數目。街頭的乞丐會減低路人的快樂，因為心腸軟的路 人看到乞丐會產生同情的痛苦，心腸硬的路人看到乞丐會產生厭惡的痛苦。那些在 收容所裡的乞丐呢？邊沁承認有些乞丐會覺得住在收容所裡比較快樂，有些會覺得 流浪在街頭比較快樂。但把收容所外的快樂和痛苦，和收容所裡的快樂和痛苦加起 來，成立收容所還是會增進社會整體的快樂。 依據上文，符合邊沁看法的選項是：', '["一般人的快樂往往建立在窮人的痛苦之上", "不同心腸的人對乞丐的痛苦感受相互抵消", "社會整體快樂感會因收容所的設置而增加", "收容所愈多將使乞丐因被迫工作而愈痛苦"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05385', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「同學們一出校門，便各奔前程。因修習的科目不同，活動的範圍自異。風雲際會， 拖青紆紫者有之；踵武陶朱，□□□□者有之；有一技之長，出人頭地者有之；而 座擁臯比，以至於吃不飽餓不死者亦有之。在校的時候，品學俱佳，□□□□，以 後未必有成就。所謂「小時了了，大未必佳」，確是不刊之論。不過一向為人卑鄙、 □□□□之輩，以後無論如何□□□□，也逃不過老同學的法眼。所以有些人迴避 老同學惟恐不及。」 以上引文共有四個缺空處，最適宜依序填入下列那一組詞語？', '["寅吃卯糧／勤奮不懈／獐頭鼠目／改頭換面", "沽名釣譽／嶔崎磊落／惡貫滿盈／賣友求榮", "乘堅策肥／巧言令色／雞鳴狗盜／英姿颯爽", "腰纏萬貫／頭角崢嶸／投機取巧／翻雲覆雨"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "380a9c199eb9", "answer_pdf_sha1": "0725574887ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05386', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '《菜根譚》：「棲守道德者，寂寞一時；依阿權勢者，淒涼萬古。達人觀物外之物， 思身後之身，寧受一時之寂寞，□□□□□□□。」 依文意及句法推敲，最適合填入空格的是：', '["幸勿依阿權勢者", "堅決棲守道德者", "毋取萬古之淒涼", "徒留千秋萬世名"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "380a9c199eb9", "answer_pdf_sha1": "0725574887ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05387', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列文句中的成語，何者使用正確？', '["他犯的只是無心之過，應該「罪不容誅」", "粗心大意的人，稿子經常是「文不加點」", "這家餐館，當年在饕客圈中「名噪一時」", "聽演講一定要「不容置喙」，才能有收穫"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "380a9c199eb9", "answer_pdf_sha1": "0725574887ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05388', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '①好山常自望中收  ②看山應悔我來遲  ③勝地每從行處過  ④賞雨最宜人散後 上列四句若可組為甲、乙兩副對聯，則甲、乙上下聯依序應是：', '["甲：", "", "；乙：", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "380a9c199eb9", "answer_pdf_sha1": "0725574887ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05389', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列詩句所歌詠的人物，何者正確？', '["聖主恩深漢文帝，憐君不遣到長沙－蘇武", "河梁羞與子卿別，攜手空餘五字詩－李陵", "烏江不是無船渡，恥向東吳再起兵－曹操", "三分割據紆籌策，萬古雲霄一羽毛－劉備 請依下文回答第6題至第7題： 《誠意伯文集》：「工之僑得良桐焉，斫而為琴，弦而鼓之，金聲而玉應，自以為天下 之美也，獻之太常。使國工視之，曰：『弗古。』還之。工之僑以歸，謀諸漆工，作斷 紋焉；又謀諸篆工，作古款焉。匣而埋諸土，期年出之，抱以適市。貴人過而見之，易 之以百金，獻諸朝。樂官傳視，皆曰：『希世之珍也。』工之僑聞之，歎曰：『悲哉世 也！豈獨一琴哉？莫不然矣。』」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "380a9c199eb9", "answer_pdf_sha1": "0725574887ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
